const __pageData = JSON.parse('{"title":"大文件上传","description":"","frontmatter":{},"headers":[{"level":2,"title":"需求分析","slug":"需求分析","link":"#需求分析","children":[]},{"level":2,"title":"什么是 web worker","slug":"什么是-web-worker","link":"#什么是-web-worker","children":[]},{"level":2,"title":"进度条功能","slug":"进度条功能","link":"#进度条功能","children":[]},{"level":2,"title":"文件秒传","slug":"文件秒传","link":"#文件秒传","children":[]},{"level":2,"title":"断点续传","slug":"断点续传","link":"#断点续传","children":[]},{"level":2,"title":"文件切片","slug":"文件切片","link":"#文件切片","children":[]},{"level":2,"title":"暂停上传","slug":"暂停上传","link":"#暂停上传","children":[]}],"relativePath":"notes/1.javaScript/基础/大文件上传.md","lastUpdated":1675736586000}');
